 1	import React, { FC, useMemo } from 'react';
 2	
 3	import { NodeModel, TemplateModel } from '@kubevirt-ui/kubevirt-api/console';
 4	import NetworkAttachmentDefinitionModel from '@kubevirt-ui/kubevirt-api/console/models/NetworkAttachmentDefinitionModel';
 5	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
 6	import { getAllowedResourceData } from '@kubevirt-utils/resources/shared';
 7	import { K8sResourceCommon, WatchK8sResults } from '@openshift-console/dynamic-plugin-sdk';
 8	import { ResourceInventoryItem } from '@openshift-console/dynamic-plugin-sdk-internal';
 9	import { K8sModel } from '@openshift-console/dynamic-plugin-sdk-internal/lib/api/common-types';
10	import { Stack, StackItem } from '@patternfly/react-core';
11	
12	import './ResourcesSection.scss';
13	
14	export type ResourcesSectionProps = {
15	  isAdmin?: boolean;
16	  resources?: WatchK8sResults<{
17	    [key: string]: K8sResourceCommon[];
18	  }>;
19	};
20	
21	const ResourcesSection: FC<ResourcesSectionProps> = ({ isAdmin, resources }) => {
22	  const templates = useMemo(
23	    () => (isAdmin ? resources?.vmTemplates : getAllowedResourceData(resources, TemplateModel)),
24	    [resources, isAdmin],
25	  );
26	  const vms = useMemo(
27	    () => (isAdmin ? resources?.vms : getAllowedResourceData(resources, VirtualMachineModel)),
28	    [resources, isAdmin],
29	  );
30	  const nads = useMemo(
31	    () =>
32	      isAdmin
33	        ? resources?.nads
34	        : getAllowedResourceData(resources, NetworkAttachmentDefinitionModel),
35	    [resources, isAdmin],
36	  );
37	
38	  return (
39	    <Stack className="kv-inventory-card__resources--container" hasGutter>
40	      <StackItem key={VirtualMachineModel.kind}>
41	        <ResourceInventoryItem
42	          dataTest="kv-inventory-card--vms"
43	          error={!!vms?.loadError}
44	          isLoading={vms?.loaded === false}
45	          kind={VirtualMachineModel as K8sModel}
46	          resources={vms?.data as K8sResourceCommon[]}
47	          showLink={isAdmin}
48	        />
49	      </StackItem>
50	      <StackItem key={TemplateModel.kind}>
51	        <ResourceInventoryItem
52	          basePath={`/k8s/all-namespaces/templates`}
53	          dataTest="kv-inventory-card--vm-templates"
54	          error={!!templates?.loadError}
55	          isLoading={templates?.loaded === false}
56	          kind={TemplateModel as K8sModel}
57	          resources={templates?.data}
58	          showLink={isAdmin}
59	        />
60	      </StackItem>
61	      <StackItem key={NodeModel.kind}>
62	        <ResourceInventoryItem
63	          dataTest="kv-inventory-card--nodes"
64	          error={!!resources?.nodes?.loadError}
65	          isLoading={resources?.nodes?.loaded === false}
66	          kind={NodeModel as K8sModel}
67	          resources={resources?.nodes?.data}
68	          showLink={isAdmin}
69	        />
70	      </StackItem>
71	      <StackItem key={NetworkAttachmentDefinitionModel.kind}>
72	        <ResourceInventoryItem
73	          dataTest="kv-inventory-card--nads"
74	          error={!!nads?.loadError}
75	          isLoading={nads?.loaded === false}
76	          kind={NetworkAttachmentDefinitionModel as K8sModel}
77	          resources={nads?.data}
78	          showLink={isAdmin}
79	          title="Network"
80	          titlePlural="Networks"
81	        />
82	      </StackItem>
83	    </Stack>
84	  );
85	};
86	
87	export default ResourcesSection;

